// frontend/src/components/Dashboard/CommissionBalanceCard.js
import React, { useState, useEffect } from 'react';
import {
  Card,
  CardContent,
  Typography,
  Box,
  Skeleton,
  Chip,
  useTheme,
  IconButton,
  Tooltip
} from '@mui/material';
import {
  AccountBalanceWallet,
  Refresh,
  TrendingUp,
  TrendingDown,
  Info
} from '@mui/icons-material';
import { toast } from 'react-toastify';

const CommissionBalanceCard = ({ hideValues = false }) => {
  const theme = useTheme();
  const [loading, setLoading] = useState(true);
  const [balanceData, setBalanceData] = useState({
    available: 0,
    used: 0,
    total: 0,
    lastUpdate: null
  });

  const fetchCommissionBalance = async () => {
    setLoading(true);
    try {
      // TODO: Implementar chamada para API de saldo de comissão
      // const response = await commissionService.getBalance();

      // Simulação por enquanto
      await new Promise(resolve => setTimeout(resolve, 1000));

      setBalanceData({
        available: 245.67,
        used: 54.33,
        total: 300.00,
        lastUpdate: new Date()
      });
    } catch (error) {
      toast.error('Erro ao carregar saldo de comissão');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCommissionBalance();
  }, []);

  const formatCurrency = (value) => {
    if (hideValues) return '$***';
    if (value === null || value === undefined) return '$0.00';
    return `$${parseFloat(value).toFixed(2)}`;
  };

  const getUsagePercentage = () => {
    if (balanceData.total === 0) return 0;
    return (balanceData.used / balanceData.total) * 100;
  };

  const getUsageColor = () => {
    const percentage = getUsagePercentage();
    if (percentage < 30) return '#4caf50'; // Verde
    if (percentage < 70) return '#ff9800'; // Laranja
    return '#f44336'; // Vermelho
  };

  return (
    <Card 
      sx={{ 
        height: '100%',
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
        color: 'white',
        transition: 'all 0.3s ease',
        '&:hover': {
          transform: 'translateY(-2px)',
          boxShadow: '0 8px 25px rgba(102, 126, 234, 0.3)'
        }
      }}
    >
      <CardContent sx={{ p: 3 }}>
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          mb: 2
        }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
            <AccountBalanceWallet sx={{ fontSize: 32, opacity: 0.9 }} />
            <Typography variant="h6" sx={{ fontWeight: 'bold' }}>
              Saldo Comissão
            </Typography>
          </Box>
          <Tooltip title="Atualizar saldo">
            <IconButton 
              onClick={fetchCommissionBalance}
              disabled={loading}
              sx={{ 
                color: 'white', 
                opacity: 0.8,
                '&:hover': { opacity: 1 }
              }}
            >
              <Refresh sx={{ fontSize: 20 }} />
            </IconButton>
          </Tooltip>
        </Box>

        {loading ? (
          <Box>
            <Skeleton variant="text" width="60%" sx={{ bgcolor: 'rgba(255,255,255,0.2)' }} />
            <Skeleton variant="text" width="40%" sx={{ bgcolor: 'rgba(255,255,255,0.2)' }} />
            <Skeleton variant="text" width="80%" sx={{ bgcolor: 'rgba(255,255,255,0.2)' }} />
          </Box>
        ) : (
          <>
            {/* Saldo Disponível */}
            <Box sx={{ mb: 2 }}>
              <Typography variant="body2" sx={{ opacity: 0.9, mb: 0.5 }}>
                Saldo Disponível
              </Typography>
              <Typography variant="h4" sx={{ fontWeight: 'bold', mb: 1 }}>
                {formatCurrency(balanceData.available)}
              </Typography>
            </Box>

            {/* Estatísticas */}
            <Box sx={{ 
              display: 'flex', 
              justifyContent: 'space-between',
              alignItems: 'center',
              mb: 2
            }}>
              <Box sx={{ textAlign: 'center' }}>
                <Typography variant="body2" sx={{ opacity: 0.8, fontSize: '0.75rem' }}>
                  Usado
                </Typography>
                <Typography variant="body1" sx={{ fontWeight: 'bold' }}>
                  {formatCurrency(balanceData.used)}
                </Typography>
              </Box>

              <Box sx={{ textAlign: 'center' }}>
                <Typography variant="body2" sx={{ opacity: 0.8, fontSize: '0.75rem' }}>
                  Total
                </Typography>
                <Typography variant="body1" sx={{ fontWeight: 'bold' }}>
                  {formatCurrency(balanceData.total)}
                </Typography>
              </Box>

              <Box sx={{ textAlign: 'center' }}>
                <Typography variant="body2" sx={{ opacity: 0.8, fontSize: '0.75rem' }}>
                  Uso
                </Typography>
                <Typography variant="body1" sx={{ fontWeight: 'bold' }}>
                  {getUsagePercentage().toFixed(1)}%
                </Typography>
              </Box>
            </Box>

            {/* Barra de Progresso */}
            <Box sx={{ mb: 2 }}>
              <Box sx={{ 
                width: '100%', 
                height: 6, 
                bgcolor: 'rgba(255,255,255,0.2)', 
                borderRadius: 3,
                overflow: 'hidden'
              }}>
                <Box sx={{ 
                  width: `${getUsagePercentage()}%`, 
                  height: '100%', 
                  bgcolor: getUsageColor(),
                  transition: 'width 0.3s ease'
                }} />
              </Box>
            </Box>

            {/* Status e Informações */}
            <Box sx={{ 
              display: 'flex', 
              alignItems: 'center', 
              justifyContent: 'space-between',
              mt: 2
            }}>
              <Chip
                size="small"
                label={getUsagePercentage() < 70 ? 'Saudável' : getUsagePercentage() < 90 ? 'Atenção' : 'Crítico'}
                sx={{
                  bgcolor: getUsageColor(),
                  color: 'white',
                  fontWeight: 'bold',
                  fontSize: '0.7rem'
                }}
              />

              {balanceData.lastUpdate && (
                <Typography variant="caption" sx={{ opacity: 0.7, fontSize: '0.7rem' }}>
                  Atualizado: {balanceData.lastUpdate.toLocaleTimeString('pt-BR', { 
                    hour: '2-digit', 
                    minute: '2-digit' 
                  })}
                </Typography>
              )}
            </Box>

            {/* Informação Adicional */}
            <Box sx={{ 
              display: 'flex', 
              alignItems: 'center', 
              gap: 1,
              mt: 2,
              pt: 2,
              borderTop: '1px solid rgba(255,255,255,0.2)'
            }}>
              <Info sx={{ fontSize: 16, opacity: 0.8 }} />
              <Typography variant="body2" sx={{ opacity: 0.8, fontSize: '0.75rem' }}>
                Usado para cobrir taxas de trading
              </Typography>
            </Box>
          </>
        )}
      </CardContent>
    </Card>
  );
};

export default CommissionBalanceCard;
